SELECT Item.[Trademark Code], Item.[Season Code], Item.[Collection Code], Item.[Line Code], Item.[Product sex], Item.[Product Family], [InventarioAllaData-step0-pre].tipo, Item.[Model Item No_], Item.[Variable Code 01] AS Colore, Item.[Variable Code 02] AS Taglia, [InventarioAllaData-step0-pre].[Item No_], [InventarioAllaData-step0-pre].[Location Code], ValutazioneMagazzino_RelazioneMagazzinoFornitorePrezzo.CodiceFonitorePerPrezzo, Sum([InventarioAllaData-step0-pre].qty) AS Paia, Sum(IIf([qty]>0,[qty])) AS PaiaEntrate, Sum(IIf([qty]<0,[qty],0)) AS PaiaUscite, Item.[advertising material]
FROM ([InventarioAllaData-step0-pre] LEFT JOIN ValutazioneMagazzino_RelazioneMagazzinoFornitorePrezzo ON [InventarioAllaData-step0-pre].[Location Code] = ValutazioneMagazzino_RelazioneMagazzinoFornitorePrezzo.CodiceMagazzino) INNER JOIN Item ON [InventarioAllaData-step0-pre].[Item No_] = Item.No_
GROUP BY Item.[Trademark Code], Item.[Season Code], Item.[Collection Code], Item.[Line Code], Item.[Product sex], Item.[Product Family], [InventarioAllaData-step0-pre].tipo, Item.[Model Item No_], Item.[Variable Code 01], Item.[Variable Code 02], [InventarioAllaData-step0-pre].[Item No_], [InventarioAllaData-step0-pre].[Location Code], ValutazioneMagazzino_RelazioneMagazzinoFornitorePrezzo.CodiceFonitorePerPrezzo, Item.[advertising material], Item.[Configurator Relation]
HAVING (((Item.[Configurator Relation])=3));

